1	<!DOCTYPE html>
2	<html lang="ko">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>AI 통합 모니터링 — 대시보드</title>
7	  <style>
8	    * { box-sizing: border-box; margin: 0; padding: 0; }
9	
10	    html, body { height: 100%; overflow: hidden; }
11	
12	    body {
13	      font-family: 'Segoe UI', 'Apple SD Gothic Neo', sans-serif;
14	      background: #0d1117;
15	      color: #e6edf3;
16	      display: flex;
17	      flex-direction: column;
18	    }
19	
20	    /* ── 상단 네비게이션 바 ── */
21	    .topbar {
22	      display: flex;
23	      align-items: center;
24	      background: #161b22;
25	      border-bottom: 1px solid #21262d;
26	      padding: 0 24px;
27	      height: 52px;
28	      flex-shrink: 0;
29	      z-index: 100;
30	    }
31	
32	    .topbar-logo {
33	      display: flex;
34	      align-items: center;
35	      gap: 10px;
36	      margin-right: 32px;
37	    }
38	    .topbar-icon {
39	      width: 28px; height: 28px; border-radius: 7px;
40	      background: linear-gradient(135deg, #1d4ed8 0%, #7c3aed 100%);
41	      display: flex; align-items: center; justify-content: center;
42	      font-size: 14px; flex-shrink: 0;
43	    }
44	    .topbar-title { font-size: 13px; font-weight: 700; color: #f0f6fc; white-space: nowrap; }
45	    .topbar-sub   { font-size: 10px; color: #6e7681; white-space: nowrap; }
46	
47	    .topbar-divider { width: 1px; height: 24px; background: #21262d; margin: 0 20px; }
48	
49	    /* ── 탭 ── */
50	    .nav-tabs { display: flex; gap: 4px; height: 100%; align-items: center; }
51	
52	    .nav-tab {
53	      display: flex; align-items: center; gap: 7px;
54	      padding: 6px 16px; border-radius: 7px;
55	      font-size: 12px; font-weight: 600;
56	      cursor: pointer; border: 1.5px solid transparent;
57	      background: transparent; color: #8b949e;
58	      transition: all 0.15s; white-space: nowrap;
59	    }
60	    .nav-tab:hover  { background: #1f2937; color: #e6edf3; }
61	    .nav-tab.active { background: #1f2937; border-color: #3b82f6; color: #60a5fa; }
62	    .nav-tab-dot { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }
63	
64	    .topbar-right {
65	      margin-left: auto;
66	      display: flex; align-items: center; gap: 10px;
67	    }
68	    .env-badge {
69	      font-size: 10px; font-weight: 700; letter-spacing: 0.5px;
70	      padding: 3px 9px; border-radius: 4px;
71	      background: #1a1200; border: 1px solid #d29922; color: #d29922;
72	    }
73	    .date-label { font-size: 10px; color: #6e7681; font-family: monospace; }
74	
75	    /* ── iframe 영역 ── */
76	    .frame-wrap { flex: 1; position: relative; overflow: hidden; }
77	
78	    .frame-pane {
79	      position: absolute;
80	      top: 0; left: 0; right: 0; bottom: 0;
81	      display: none;
82	    }
83	    .frame-pane.active { display: block; }
84	
85	    .frame-pane iframe {
86	      width: 100%; height: 100%;
87	      border: none; background: #0d1117;
88	    }
89	  </style>
90	</head>
91	<body>
92	
93	<!-- ══ 상단 네비게이션 바 ══ -->
94	<div class="topbar">
95	
96	  <div class="topbar-logo">
97	    <div class="topbar-icon">🤖</div>
98	    <div>
99	      <div class="topbar-title">AI Agent 기반 지능형 통합 모니터링 고도화</div>
100	      <div class="topbar-sub">폐쇄망 환경 · Grafana + Ollama + Prometheus + Loki</div>
101	    </div>
102	  </div>
103	
104	  <div class="topbar-divider"></div>
105	
106	  <div class="nav-tabs">
107	    <button class="nav-tab active" onclick="showPane(0)">
108	      <div class="nav-tab-dot" style="background:#3b82f6;"></div>
109	      전체 아키텍처
110	    </button>
111	    <button class="nav-tab" onclick="showPane(1)">
112	      <div class="nav-tab-dot" style="background:#a855f7;"></div>
113	      AI 분석 파이프라인 흐름
114	    </button>
115	  </div>
116	
117	  <div class="topbar-right">
118	    <span class="env-badge">폐쇄망</span>
119	    <span class="date-label" id="clock"></span>
120	  </div>
121	
122	</div>
123	
124	<!-- ══ iframe 패널 ══ -->
125	<div class="frame-wrap">
126	  <div class="frame-pane active" id="pane-0">
127	    <iframe src="architecture.html" title="전체 아키텍처"></iframe>
128	  </div>
129	  <div class="frame-pane" id="pane-1">
130	    <iframe src="flow.html" title="AI 분석 파이프라인 흐름"></iframe>
131	  </div>
132	</div>
133	
134	<script>
135	  function showPane(idx) {
136	    document.querySelectorAll('.nav-tab').forEach((t, i) => t.classList.toggle('active', i === idx));
137	    document.querySelectorAll('.frame-pane').forEach((p, i) => p.classList.toggle('active', i === idx));
138	  }
139	
140	  function updateClock() {
141	    const now = new Date();
142	    const pad = n => String(n).padStart(2, '0');
143	    document.getElementById('clock').textContent =
144	      `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}  ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
145	  }
146	  updateClock();
147	  setInterval(updateClock, 1000);
148	</script>
149	
150	</body>
151	</html>
